import React, { useState, useEffect } from 'react';
import { doc, updateDoc, collection, query, where, getDocs, limit, orderBy } from 'firebase/firestore';
import { db } from '../../firebase/config';
import { useAuction } from '../../context/AuctionContext';
import { Play, Pause, Square, UserPlus, FastForward, CheckCircle, AlertCircle } from 'lucide-react';

export const AuctionController = () => {
    const { auctionState } = useAuction();
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const auctionRef = doc(db, 'settings', 'auction');

    const updateStatus = async (newStatus) => {
        setLoading(true);
        setError('');
        try {
            if (newStatus === 'live' && auctionState?.status === 'idle') {
                // Check if we have a current player before starting, if not try to assign one
                if (!auctionState?.currentPlayerId) {
                    const success = await nextPlayer();
                    if (!success) {
                        throw new Error("Cannot start auction: No upcoming players found.");
                    }
                }
            }

            await updateDoc(auctionRef, { status: newStatus });
        } catch (err) {
            console.error(err);
            setError(err.message || 'Failed to update status');
        } finally {
            setLoading(false);
        }
    };

    const nextPlayer = async () => {
        setLoading(true);
        setError('');
        let success = false;
        try {
            // Find the next upcoming player
            const q = query(
                collection(db, 'players'),
                where('status', '==', 'upcoming'),
                orderBy('createdAt', 'asc'),
                limit(1)
            );

            const querySnapshot = await getDocs(q);

            if (!querySnapshot.empty) {
                const nextDoc = querySnapshot.docs[0];

                // Update old player to unsold if they were just live and nobody bid
                if (auctionState?.currentPlayerId) {
                    const oldPlayerRef = doc(db, 'players', auctionState.currentPlayerId);
                    // We'll just mark them unsold here for safety; the timer logic should normally handle sold/unsold transitions automatically.
                    // However, if the admin manually forces "next", we assume the current goes unsold.
                    await updateDoc(oldPlayerRef, { status: 'unsold', round: (auctionState.roundNumber || 1) + 1 });
                }

                // Make new player live
                await updateDoc(doc(db, 'players', nextDoc.id), { status: 'live' });

                // Reset auction settings for new player
                await updateDoc(auctionRef, {
                    currentPlayerId: nextDoc.id,
                    currentBid: 0,
                    leadingTeamId: null,
                    timerSeconds: 30,
                    status: 'live'
                });
                success = true;
            } else {
                // Handle round 2 logic: If no 'upcoming', try to find 'unsold' from previous rounds
                const round2Q = query(
                    collection(db, 'players'),
                    where('status', '==', 'unsold'),
                    orderBy('round', 'asc'),
                    limit(1)
                );
                const round2Snap = await getDocs(round2Q);

                if (!round2Snap.empty) {
                    const nextDoc = round2Snap.docs[0];
                    await updateDoc(doc(db, 'players', nextDoc.id), { status: 'live' });

                    await updateDoc(auctionRef, {
                        currentPlayerId: nextDoc.id,
                        currentBid: 0,
                        leadingTeamId: null,
                        timerSeconds: 30,
                        status: 'live',
                        roundNumber: (auctionState.roundNumber || 1) + 1
                    });
                    success = true;
                } else {
                    setError('No players left to auction!');
                }
            }
        } catch (err) {
            console.error(err);
            setError('Failed to fetch next player');
        } finally {
            setLoading(false);
        }
        return success;
    };

    const handleForceUnsold = async () => {
        setLoading(true);
        setError('');
        try {
            if (!auctionState?.currentPlayerId) throw new Error("No active player.");

            const playerRef = doc(db, 'players', auctionState.currentPlayerId);
            await updateDoc(playerRef, {
                status: 'unsold',
                round: (auctionState.roundNumber || 1) + 1
            });

            await updateDoc(auctionRef, {
                status: 'paused',
                currentPlayerId: null,
                currentBid: 0,
                leadingTeamId: null
            });
        } catch (err) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    const isLive = auctionState?.status === 'live';
    const isPaused = auctionState?.status === 'paused';
    const isIdle = auctionState?.status === 'idle';

    return (
        <div className="space-y-6 relative z-10">

            {error && (
                <div className="p-3 bg-red-500/10 border border-red-500/20 rounded-lg flex items-start text-red-400">
                    <AlertCircle size={18} className="mr-2 mt-0.5 flex-shrink-0" />
                    <span className="text-sm">{error}</span>
                </div>
            )}

            {/* Main Action Buttons */}
            <div className="grid grid-cols-2 gap-4">
                {isIdle || isPaused ? (
                    <button
                        onClick={() => updateStatus('live')}
                        disabled={loading}
                        className="flex flex-col items-center justify-center p-4 bg-brand-neon/10 border border-brand-neon/30 text-brand-neon rounded-xl hover:bg-brand-neon hover:text-black transition-colors"
                    >
                        <Play size={32} className="mb-2" />
                        <span className="font-bold uppercase tracking-wider text-sm">{isPaused ? 'Resume' : 'Start'}</span>
                    </button>
                ) : (
                    <button
                        onClick={() => updateStatus('paused')}
                        disabled={loading}
                        className="flex flex-col items-center justify-center p-4 bg-yellow-500/10 border border-yellow-500/30 text-yellow-500 rounded-xl hover:bg-yellow-500 hover:text-black transition-colors"
                    >
                        <Pause size={32} className="mb-2" />
                        <span className="font-bold uppercase tracking-wider text-sm">Pause</span>
                    </button>
                )}

                <button
                    onClick={() => updateStatus('ended')}
                    disabled={loading || auctionState?.status === 'ended'}
                    className="flex flex-col items-center justify-center p-4 bg-red-500/10 border border-red-500/30 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-colors"
                >
                    <Square size={32} className="mb-2" />
                    <span className="font-bold uppercase tracking-wider text-sm">End</span>
                </button>
            </div>

            <div className="h-px bg-gray-800 w-full" />

            {/* Player flow controls */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <button
                    onClick={nextPlayer}
                    disabled={loading || isLive}
                    title={isLive ? "Pause auction to skip player" : ""}
                    className="flex items-center justify-center p-4 bg-brand-darker border border-gray-700 text-white rounded-xl hover:bg-gray-800 hover:border-gray-500 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    <FastForward size={20} className="mr-2" />
                    <span className="font-bold tracking-wide text-sm">NEXT PLAYER</span>
                </button>

                <button
                    onClick={handleForceUnsold}
                    disabled={loading || !auctionState?.currentPlayerId}
                    className="flex items-center justify-center p-4 bg-brand-darker border border-gray-700 text-white rounded-xl hover:bg-red-900/40 hover:text-red-400 hover:border-red-900 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    <AlertCircle size={20} className="mr-2" />
                    <span className="font-bold tracking-wide text-sm">FORCE UNSOLD</span>
                </button>
            </div>

        </div>
    );
};

import React, { useState } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { Menu, X, Home, Users, UserSquare, Radio, LogIn, LogOut, LayoutDashboard } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { signOut } from 'firebase/auth';
import { auth } from '../../firebase/config';

export const Navbar = () => {
    const [isOpen, setIsOpen] = useState(false);
    const location = useLocation();
    const navigate = useNavigate();
    const { currentUser, userRole } = useAuth();

    const isLive = location.pathname === '/live';

    const handleLogout = async () => {
        try {
            await signOut(auth);
            navigate('/');
        } catch (error) {
            console.error('Logout error', error);
        }
    };

    const navLinks = [
        { name: 'Home', path: '/', icon: <Home size={18} /> },
        { name: 'Teams', path: '/teams', icon: <Users size={18} /> },
        { name: 'Players', path: '/players', icon: <UserSquare size={18} /> },
        { name: 'Live Auction', path: '/live', icon: <Radio size={18} className="text-red-500 animate-pulse" /> },
    ];

    return (
        <nav className="bg-brand-dark border-b border-gray-800 sticky top-0 z-50">
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                <div className="flex justify-between h-16">
                    <div className="flex items-center">
                        <Link to="/" className="flex-shrink-0 flex items-center">
                            <span className="text-2xl font-black text-brand-neon tracking-tighter italic">NPL</span>
                            <span className="ml-2 text-white font-bold hidden sm:block">AUCTION '26</span>
                        </Link>
                    </div>

                    {/* Desktop Menu */}
                    <div className="hidden md:flex items-center space-x-4">
                        {navLinks.map((link) => (
                            <Link
                                key={link.path}
                                to={link.path}
                                className={`flex items-center px-3 py-2 rounded-md text-sm font-medium transition-colors ${location.pathname === link.path
                                        ? 'bg-gray-800 text-brand-neon'
                                        : 'text-gray-300 hover:bg-gray-700 hover:text-white'
                                    }`}
                            >
                                <span className="mr-2">{link.icon}</span>
                                {link.name}
                            </Link>
                        ))}

                        {currentUser ? (
                            <div className="flex items-center space-x-4 ml-4 pl-4 border-l border-gray-700">
                                <Link
                                    to={userRole === 'organizer' ? '/admin-dashboard' : '/owner-dashboard'}
                                    className="flex items-center text-gray-300 hover:text-brand-neon transition-colors text-sm font-medium"
                                >
                                    <LayoutDashboard size={18} className="mr-2" />
                                    Dashboard
                                </Link>
                                <button
                                    onClick={handleLogout}
                                    className="flex items-center text-gray-400 hover:text-red-400 transition-colors text-sm font-medium"
                                >
                                    <LogOut size={18} className="mr-2" />
                                    Logout
                                </button>
                            </div>
                        ) : null}
                    </div>

                    {/* Mobile menu button */}
                    <div className="flex items-center md:hidden">
                        <button
                            onClick={() => setIsOpen(!isOpen)}
                            className="inline-flex items-center justify-center p-2 rounded-md text-gray-400 hover:text-white hover:bg-gray-700 focus:outline-none"
                        >
                            {isOpen ? <X size={24} /> : <Menu size={24} />}
                        </button>
                    </div>
                </div>
            </div>

            {/* Mobile Menu Dropdown */}
            {isOpen && (
                <div className="md:hidden bg-brand-dark border-b border-gray-800">
                    <div className="px-2 pt-2 pb-3 space-y-1 sm:px-3">
                        {navLinks.map((link) => (
                            <Link
                                key={link.path}
                                to={link.path}
                                onClick={() => setIsOpen(false)}
                                className={`flex items-center px-3 py-2 rounded-md text-base font-medium ${location.pathname === link.path
                                        ? 'bg-gray-800 text-brand-neon'
                                        : 'text-gray-300 hover:bg-gray-700 hover:text-white'
                                    }`}
                            >
                                <span className="mr-3">{link.icon}</span>
                                {link.name}
                            </Link>
                        ))}

                        {currentUser && (
                            <>
                                <div className="border-t border-gray-700 my-2 pt-2"></div>
                                <Link
                                    to={userRole === 'organizer' ? '/admin-dashboard' : '/owner-dashboard'}
                                    onClick={() => setIsOpen(false)}
                                    className="flex items-center px-3 py-2 rounded-md text-base font-medium text-gray-300 hover:bg-gray-700 hover:text-white"
                                >
                                    <LayoutDashboard size={18} className="mr-3" />
                                    Dashboard
                                </Link>
                                <button
                                    onClick={() => { handleLogout(); setIsOpen(false); }}
                                    className="w-full flex items-center px-3 py-2 rounded-md text-base font-medium text-gray-400 hover:bg-gray-700 hover:text-red-400"
                                >
                                    <LogOut size={18} className="mr-3" />
                                    Logout
                                </button>
                            </>
                        )}
                    </div>
                </div>
            )}
        </nav>
    );
};

import React, { createContext, useContext, useEffect, useState } from 'react';
import { doc, onSnapshot } from 'firebase/firestore';
import { db } from '../firebase/config';

const AuctionContext = createContext();

export const useAuction = () => useContext(AuctionContext);

export const AuctionProvider = ({ children }) => {
    const [auctionState, setAuctionState] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        // Listen to the global auction settings
        const auctionRef = doc(db, 'settings', 'auction');

        const unsubscribe = onSnapshot(auctionRef, (docSnap) => {
            if (docSnap.exists()) {
                setAuctionState(docSnap.data());
            } else {
                setAuctionState(null);
            }
            setLoading(false);
        }, (error) => {
            console.error("Error fetching auction state:", error);
            setLoading(false);
        });

        return () => unsubscribe();
    }, []);

    const value = {
        auctionState,
        loading
    };

    return (
        <AuctionContext.Provider value={value}>
            {children}
        </AuctionContext.Provider>
    );
};

import React, { createContext, useContext, useEffect, useState } from 'react';
import { onAuthStateChanged } from 'firebase/auth';
import { doc, getDoc } from 'firebase/firestore';
import { auth, db } from '../firebase/config';

const AuthContext = createContext();

export const useAuth = () => useContext(AuthContext);

export const AuthProvider = ({ children }) => {
    const [currentUser, setCurrentUser] = useState(null);
    const [userRole, setUserRole] = useState(null); // 'organizer' | 'owner' | null
    const [userTeamId, setUserTeamId] = useState(null); // only if owner
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const unsubscribe = onAuthStateChanged(auth, async (user) => {
            setLoading(true);
            if (user) {
                setCurrentUser(user);
                try {
                    // Fetch role from users collection
                    const userDoc = await getDoc(doc(db, 'users', user.uid));
                    if (userDoc.exists()) {
                        const data = userDoc.data();
                        setUserRole(data.role);
                        if (data.role === 'owner') {
                            setUserTeamId(data.teamId);
                        }
                    } else {
                        setUserRole(null);
                        setUserTeamId(null);
                    }
                } catch (error) {
                    console.error("Error fetching user data:", error);
                }
            } else {
                setCurrentUser(null);
                setUserRole(null);
                setUserTeamId(null);
            }
            setLoading(false);
        });

        return unsubscribe;
    }, []);

    const value = {
        currentUser,
        userRole,
        userTeamId,
        loading
    };

    return (
        <AuthContext.Provider value={value}>
            {!loading && children}
        </AuthContext.Provider>
    );
};

import { useState } from 'react';
import { doc, runTransaction } from 'firebase/firestore';
import { db } from '../../firebase/config';
import { useAuction } from '../../context/AuctionContext';
import { useAuth } from '../../context/AuthContext';

export const useBidTransaction = () => {
    const { auctionState } = useAuction();
    const { userTeamId, currentUser } = useAuth();
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const placeBid = async () => {
        if (!auctionState || auctionState.status !== 'live') {
            setError('Auction is not live');
            return false;
        }

        if (!userTeamId) {
            setError('You are not assigned to a team');
            return false;
        }

        if (auctionState.leadingTeamId === userTeamId) {
            setError('You already hold the highest bid');
            return false;
        }

        setLoading(true);
        setError('');

        try {
            const nextBidAmount = auctionState.currentBid === 0 ? auctionState.basePrice : auctionState.currentBid + auctionState.increment;

            const auctionRef = doc(db, 'settings', 'auction');
            const teamRef = doc(db, 'teams', userTeamId);

            await runTransaction(db, async (transaction) => {
                const teamDoc = await transaction.get(teamRef);
                if (!teamDoc.exists()) {
                    throw new Error('Team does not exist');
                }

                const teamData = teamDoc.data();
                if (teamData.wallet < nextBidAmount) {
                    throw new Error('Insufficient wallet balance');
                }

                if (teamData.squadCount >= (teamData.maxPlayers || 15)) {
                    throw new Error('Squad is full');
                }

                // We could also check if the auction state changed midway, but transactions handle concurrent writes.
                // We update the auction state
                transaction.update(auctionRef, {
                    currentBid: nextBidAmount,
                    leadingTeamId: userTeamId,
                    // Timer reset logic could go here if requirement specifies it, typically timer resets to 30 on bid:
                    timerSeconds: 30
                });
            });

            return true;
        } catch (err) {
            console.error(err);
            setError(err.message || 'Transaction failed');
            return false;
        } finally {
            setLoading(false);
        }
    };

    return { placeBid, loading, error };
};

