import React, { useEffect, useState, useRef } from 'react';
import { doc, getDoc, updateDoc } from 'firebase/firestore';
import { db } from '../firebase/config';
import { useAuction } from '../context/AuctionContext';
import { User, Trophy, Clock, CheckCircle, AlertCircle } from 'lucide-react';

export default function LiveAuction() {
    const { auctionState, loading } = useAuction();
    const [playerInfo, setPlayerInfo] = useState(null);
    const [leadingTeam, setLeadingTeam] = useState(null);
    const [timeLeft, setTimeLeft] = useState(30);

    // To avoid spamming Firestore, we run the timer locally and let Admin/Owner actions reset it.
    // In a full production app, you might use a Cloud Function for trusted time,
    // but for serverless we can use local interval synced to the state.timerSeconds
    const timerRef = useRef(null);

    useEffect(() => {
        const fetchCurrentData = async () => {
