import React, { useEffect, useState } from 'react';
import { doc, getDoc, onSnapshot } from 'firebase/firestore';
import { db } from '../firebase/config';
import { useAuth } from '../context/AuthContext';
import { LiveBidButton } from '../components/owner/LiveBidButton';
import { Wallet, Users, AlertCircle } from 'lucide-react';

export default function OwnerDashboard() {
    const { userTeamId, loading: authLoading } = useAuth();
    const [teamData, setTeamData] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (!userTeamId) {
            setLoading(false);
            return;
        }

        const teamRef = doc(db, 'teams', userTeamId);

        // Listen to real-time wallet deduction updates
        const unsubscribe = onSnapshot(teamRef, (docSnap) => {
            if (docSnap.exists()) {
                setTeamData(docSnap.data());
            }
            setLoading(false);
        }, (error) => {
            console.error("Error fetching team data:", error);
            setLoading(false);
        });

        return () => unsubscribe();
    }, [userTeamId]);

    if (authLoading || loading) {
        return <div className="p-6 text-center text-white">Loading Owner Dashboard...</div>;
    }

    if (!userTeamId) {
        return (
            <div className="min-h-[70vh] flex items-center justify-center p-6 text-white text-center">
                <div className="bg-red-500/10 border border-red-500/20 p-8 rounded-xl max-w-md">
                    <AlertCircle size={48} className="text-red-500 mx-auto mb-4" />
                    <h2 className="text-xl font-bold mb-2">No Team Assigned</h2>
                    <p className="text-gray-400">Your account is not assigned to any team. Please ask the organizer to assign you.</p>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-brand-darker text-white p-4 sm:p-6 pb-24 lg:pb-6 relative overflow-hidden">
            {/* Background neon effect */}
            <div className="fixed top-20 right-20 w-64 h-64 bg-brand-neon/5 rounded-full blur-[100px] pointer-events-none"></div>

            <div className="max-w-7xl mx-auto space-y-6 relative z-10">
                <header className="border-b border-gray-800 pb-6 mb-8 flex flex-col md:flex-row md:items-end justify-between">
                    <div>
                        <h1 className="text-4xl md:text-5xl font-black text-white tracking-tighter uppercase">{teamData?.name || 'Your Team'}</h1>
                        <p className="text-brand-neon font-bold tracking-widest mt-1 text-sm">{teamData?.shortName || ''}</p>
                    </div>
                </header>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

                    {/* Stats Cards */}
                    <div className="space-y-6">
                        <div className="bg-brand-dark rounded-xl border border-gray-800 p-6 flex items-center justify-between shadow-lg">
                            <div>
                                <p className="text-sm font-bold text-gray-500 uppercase tracking-widest mb-1">Available Wallet</p>
                                <p className="text-4xl font-black text-brand-neon tracking-tighter">
                                    Γé╣{teamData?.wallet?.toLocaleString() || 0}
                                </p>
                            </div>
                            <div className="p-4 bg-brand-neon/10 rounded-full">
                                <Wallet size={32} className="text-brand-neon" />
                            </div>
                        </div>

                        <div className="bg-brand-dark rounded-xl border border-gray-800 p-6 flex items-center justify-between shadow-lg">
                            <div>
                                <p className="text-sm font-bold text-gray-500 uppercase tracking-widest mb-1">Squad Strength</p>
                                <p className="text-4xl font-black text-white tracking-tighter">
                                    {teamData?.squadCount || 0} <span className="text-xl text-gray-600">/ {teamData?.maxPlayers || 15}</span>
                                </p>
                            </div>
                            <div className="p-4 bg-gray-800 rounded-full">
                                <Users size={32} className="text-gray-400" />
                            </div>
                        </div>
                    </div>

                    {/* Bidding Area */}
                    <div className="bg-brand-dark rounded-xl border border-gray-800 p-6 shadow-2xl flex flex-col items-center justify-center min-h-[300px] relative border-t-2 border-t-brand-neon/50">
                        <div className="absolute inset-0 bg-gradient-to-b from-brand-neon/5 to-transparent rounded-xl pointer-events-none"></div>
                        <h2 className="text-lg font-bold text-gray-300 uppercase tracking-widest mb-8">Live Action Command</h2>

                        <LiveBidButton />
                    </div>

                </div>
            </div>
        </div>
    );
}
